parameters.jsonBody:
{
  "model": "deepseek-r1:1.5b",
  "messages": [
    {
      "role": "system",
      "content": "You generate structured lesson question banks for a data science learning app.

You are given the full LESSON_TEXT plus some metadata. Your task:

1. Understand the lesson and keep its scope.
2. Create a small set of 8–20 short-answer questions whose answers are fully determined by the lesson.
3. For each question, also provide a concise answer.
4. Classify each question with a simple category and difficulty level (1=easy, 2=medium, 3=hard).

Return ONLY valid JSON with this exact schema:

{
  "lesson": {
    "slug": string,
    "title": string,
    "topic": string,
    "level": number
  },
  "questions": [
    {
      "question": string,
      "answer": string,
      "difficulty": number,
      "category": string,
      "question_type": "short_answer"
    }
  ]
}

Do not include any Markdown code fences, explanations, or extra text. Just the JSON."
    },
    {
      "role": "user",
      "content": "Lesson metadata:
- slug: {{ $json.lesson_slug }}
- title: {{ $json.lesson_title }}
- topic: {{ $json.topic }}
- level: {{ $json.level }}

LESSON_TEXT:
{{ $json.lesson_text }}"
    }
  ],
  "temperature": 0.2
}

parameters.functionCode:
// Parse DeepSeek bundle and emit one item per question with lesson metadata.

// DeepSeek returns an OpenAI-style response; JSON bundle is inside choices[0].message.content.
const raw =
  $json.choices &&
  Array.isArray($json.choices) &&
  $json.choices[0] &&
  $json.choices[0].message &&
  typeof $json.choices[0].message.content === 'string'
    ? $json.choices[0].message.content.trim()
    : '';

if (!raw) {
  throw new Error('LLM response is empty or missing choices[0].message.content');
}

let bundle;
try {
  bundle = JSON.parse(raw);
} catch (err) {
  throw new Error(
    'Failed to parse LLM JSON: ' +
      err.message +
      '\nRaw content (first 500 chars):\n' +
      raw.slice(0, 500)
  );
}

const lesson = bundle.lesson || {};
const questions = Array.isArray(bundle.questions) ? bundle.questions : [];

// Get original metadata from the Set node (first item)
const metaItems = $node['Set – Lesson Metadata'].json;
const metaNode = Array.isArray(metaItems) ? metaItems[0] : metaItems || {};

return questions.map((q, index) => ({
  json: {
    // lesson-level data
    lesson_slug: lesson.slug || metaNode.lesson_slug,
    lesson_title: lesson.title || metaNode.lesson_title,
    topic: lesson.topic || metaNode.topic,
    level:
      typeof lesson.level === 'number'
        ? lesson.level
        : metaNode.level,

    // question-level data
    question: q.question,
    answer: q.answer,
    difficulty:
      typeof q.difficulty === 'number' ? q.difficulty : 1,
    category: q.category || 'unspecified',
    question_type: q.question_type || 'short_answer',
    source: 'baseline',
    index
  }
}));
